const body = $input.first().json.body;

if (body?.hub?.challenge) {
  return [{ json: { isVerification: true, challenge: body.hub.challenge } }];
}

const entry   = body?.entry?.[0];
const change  = entry?.changes?.[0];
const message = change?.value?.messages?.[0];
const contact = change?.value?.contacts?.[0];

if (!message) return [{ json: { skip: true } }];

const phoneFrom   = message.from;
const messageText = message?.text?.body || message?.button?.text || '';
const displayName = contact?.profile?.name || 'Paciente';

// ─── CONFIGURA ESTE VALOR POR CLIENTE ───────────────────────────────────────
const CLIENTE_ID = 1;  // ID del cliente en la tabla `clientes` de la DB
// ─────────────────────────────────────────────────────────────────────────────

const esc = s => String(s || '').replace(/'/g, "''").substring(0, 1000);

return [{
  json: {
    phoneFrom,
    messageText,
    messageType: message.type,
    displayName,
    timestamp: message.timestamp,
    skip: false,
    clienteId: CLIENTE_ID,
    canalId: phoneFrom.replace(/[^0-9]/g, ''),
    textEsc: esc(messageText),
    nameEsc: esc(displayName)
  }
}];
